# @cctt_verify {"v":2,"sym":"sympy.core.tests.test_function.test_Lambda_equality","kind":"function","src_hash":"50391f1588aab877","in":{"base":"Any"},"out":{"base":"Any","pred":"Lambda((x, y), 2 * x) == Lambda((x, y), 2 * x) and Lambda(x, 2 * x) != Lambda((x, y), 2 * x) and Lambda(x, 2 * x) != 2 * x and Lambda(x, 2 * x) != Lambda(y, 2 * y)"},"spec":{"lhs":"test_Lambda_equality()","rhs":"test_Lambda_equality produces the expected output","over":{"base":"Any"},"name":"test_Lambda_equality_correct"},"guarantee":"test_Lambda_equality produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.core.tests.test_function.test_Lambda_equality_correct","statement":"Path(test_Lambda_equality(x), test_Lambda_equality produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"51f0b91175b6a71c"}
def test_Lambda_equality():
    assert Lambda((x, y), 2*x) == Lambda((x, y), 2*x)
    # these, of course, should never be equal
    assert Lambda(x, 2*x) != Lambda((x, y), 2*x)
    assert Lambda(x, 2*x) != 2*x
    # But it is tempting to want expressions that differ only
    # in bound symbols to compare the same.  But this is not what
    # Python's `==` is intended to do; two objects that compare
    # as equal means that they are indistibguishable and cache to the
    # same value.  We wouldn't want to expression that are
    # mathematically the same but written in different variables to be
    # interchanged else what is the point of allowing for different
    # variable names?
    assert Lambda(x, 2*x) != Lambda(y, 2*y)


