# @cctt_verify {"v":2,"sym":"sympy.core.tests.test_function.test_Subs","kind":"function","src_hash":"d87ca9c29442e377","in":{"base":"Any"},"out":{"base":"Any","pred":"Subs(1, (), ()) is S.One and Subs(x, y, z) != Subs(x, y, 1) and Subs(x, x, 1).subs(x, y).has(y) and Subs(Derivative(f(x), (x, 2)), x, x).doit() == f(x).diff(x, x) and Subs(x, x, 0).has(x) and not Subs(x, x, 0).free_symbols and Subs(Subs(x + y, x, 2), y, 1) == Subs(x + y, (x, y), (2, 1)) and Subs(x, (x,), (0,)) == Subs(x, x, 0) and Subs(x, x, 0) == Subs(y, y, 0) and Subs(x, x, 0).subs(x, 1) == Subs(x, x, 0) and Subs(y, x, 0).subs(y, 1) == Subs(1, x, 0) and Subs(f(x), x, 0).doit() == f(0) and Subs(f(x ** 2), x ** 2, 0).doit() == f(0) and Subs(x, y, 2).subs(x, y).doit() == 2 and Subs(f(x, y), (x, y, z), (0, 1, 1)) != Subs(f(x, y) + z, (x, y, z), (0, 1, 0)) and Subs(f(x, y), (x, y), (0, 1)).doit() == f(0, 1) and Subs(Subs(f(x, y), x, 0), y, 1).doit() == f(0, 1) and len(Subs(f(x, y), (x, y), (0, 1)).variables) == 2 and Subs(f(x, y), (x, y), (0, 1)).point == Tuple(0, 1) and Subs(f(x), x, 0) == Subs(f(y), y, 0) and Subs(f(x, y), (x, y), (0, 1)) == Subs(f(x, y), (y, x), (1, 0)) and Subs(f(x) * y, (x, y), (0, 1)) == Subs(f(y) * x, (y, x), (0, 1)) and Subs(f(x) * y, (x, y), (1, 1)) == Subs(f(y) * x, (x, y), (1, 1)) and Subs(f(x), x, 0).subs(x, 1).doit() == f(0) and Subs(f(x), x, y).subs(y, 0) == Subs(f(x), x, 0) and Subs(y * f(x), x, y).subs(y, 2) == Subs(2 * f(x), x, 2) and (2 * Subs(f(x), x, 0)).subs(Subs(f(x), x, 0), y) == 2 * y and Subs(f(x), x, 0).free_symbols == set() and Subs(f(x, y), x, z).free_symbols == {y, z} and Subs(f(x).diff(x), x, 0).doit() and Subs(1 + f(x).diff(x), x, 0).doit() and Subs(y ** 2 * f(x), x, 0).diff(y) == 2 * y * f(0) and e.diff(y) == e.doit().diff(y) == y ** 2 * Derivative(f(y), y) + 2 * y * f(y) and Subs(f(x), x, 0) + Subs(f(x), x, 0) == 2 * Subs(f(x), x, 0) and e1 + e2 == 2 * e1 and e1.__hash__() == e2.__hash__() and Subs(z * f(x + 1), x, 1) not in [e1, e2] and Derivative(f(x), x).subs(x, g(x)) == Derivative(f(g(x)), g(x)) and Derivative(f(x), x).subs(x, x + y) == Subs(Derivative(f(x), x), x, x + y) and f(x).diff(x).subs(x, 0).subs(x, y) == f(x).diff(x).subs(x, 0) and (x * f(x).diff(x).subs(x, 0)).subs(x, y) == y * f(x).diff(x).subs(x, 0) and Subs(Derivative(g(x) ** 2, g(x), x), g(x), exp(x)).doit() == 2 * exp(x)"},"spec":{"lhs":"test_Subs()","rhs":"test_Subs produces the expected output","over":{"base":"Any"},"name":"test_Subs_correct"},"guarantee":"test_Subs produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.core.tests.test_function.test_Subs_correct","statement":"Path(test_Subs(x), test_Subs produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"6dd335bb59a5df0d"}
def test_Subs():
    assert Subs(1, (), ()) is S.One
    # check null subs influence on hashing
    assert Subs(x, y, z) != Subs(x, y, 1)
    # neutral subs works
    assert Subs(x, x, 1).subs(x, y).has(y)
    # self mapping var/point
    assert Subs(Derivative(f(x), (x, 2)), x, x).doit() == f(x).diff(x, x)
    assert Subs(x, x, 0).has(x)  # it's a structural answer
    assert not Subs(x, x, 0).free_symbols
    assert Subs(Subs(x + y, x, 2), y, 1) == Subs(x + y, (x, y), (2, 1))
    assert Subs(x, (x,), (0,)) == Subs(x, x, 0)
    assert Subs(x, x, 0) == Subs(y, y, 0)
    assert Subs(x, x, 0).subs(x, 1) == Subs(x, x, 0)
    assert Subs(y, x, 0).subs(y, 1) == Subs(1, x, 0)
    assert Subs(f(x), x, 0).doit() == f(0)
    assert Subs(f(x**2), x**2, 0).doit() == f(0)
    assert Subs(f(x, y, z), (x, y, z), (0, 1, 1)) != \
        Subs(f(x, y, z), (x, y, z), (0, 0, 1))
    assert Subs(x, y, 2).subs(x, y).doit() == 2
    assert Subs(f(x, y), (x, y, z), (0, 1, 1)) != \
        Subs(f(x, y) + z, (x, y, z), (0, 1, 0))
    assert Subs(f(x, y), (x, y), (0, 1)).doit() == f(0, 1)
    assert Subs(Subs(f(x, y), x, 0), y, 1).doit() == f(0, 1)
    raises(ValueError, lambda: Subs(f(x, y), (x, y), (0, 0, 1)))
    raises(ValueError, lambda: Subs(f(x, y), (x, x, y), (0, 0, 1)))

    assert len(Subs(f(x, y), (x, y), (0, 1)).variables) == 2
    assert Subs(f(x, y), (x, y), (0, 1)).point == Tuple(0, 1)

    assert Subs(f(x), x, 0) == Subs(f(y), y, 0)
    assert Subs(f(x, y), (x, y), (0, 1)) == Subs(f(x, y), (y, x), (1, 0))
    assert Subs(f(x)*y, (x, y), (0, 1)) == Subs(f(y)*x, (y, x), (0, 1))
    assert Subs(f(x)*y, (x, y), (1, 1)) == Subs(f(y)*x, (x, y), (1, 1))

    assert Subs(f(x), x, 0).subs(x, 1).doit() == f(0)
    assert Subs(f(x), x, y).subs(y, 0) == Subs(f(x), x, 0)
    assert Subs(y*f(x), x, y).subs(y, 2) == Subs(2*f(x), x, 2)
    assert (2 * Subs(f(x), x, 0)).subs(Subs(f(x), x, 0), y) == 2*y

    assert Subs(f(x), x, 0).free_symbols == set()
    assert Subs(f(x, y), x, z).free_symbols == {y, z}

    assert Subs(f(x).diff(x), x, 0).doit(), Subs(f(x).diff(x), x, 0)
    assert Subs(1 + f(x).diff(x), x, 0).doit(), 1 + Subs(f(x).diff(x), x, 0)
    assert Subs(y*f(x, y).diff(x), (x, y), (0, 2)).doit() == \
        2*Subs(Derivative(f(x, 2), x), x, 0)
    assert Subs(y**2*f(x), x, 0).diff(y) == 2*y*f(0)

    e = Subs(y**2*f(x), x, y)
    assert e.diff(y) == e.doit().diff(y) == y**2*Derivative(f(y), y) + 2*y*f(y)

    assert Subs(f(x), x, 0) + Subs(f(x), x, 0) == 2*Subs(f(x), x, 0)
    e1 = Subs(z*f(x), x, 1)
    e2 = Subs(z*f(y), y, 1)
    assert e1 + e2 == 2*e1
    assert e1.__hash__() == e2.__hash__()
    assert Subs(z*f(x + 1), x, 1) not in [ e1, e2 ]
    assert Derivative(f(x), x).subs(x, g(x)) == Derivative(f(g(x)), g(x))
    assert Derivative(f(x), x).subs(x, x + y) == Subs(Derivative(f(x), x),
        x, x + y)
    assert Subs(f(x)*cos(y) + z, (x, y), (0, pi/3)).n(2) == \
        Subs(f(x)*cos(y) + z, (x, y), (0, pi/3)).evalf(2) == \
        z + Rational('1/2').n(2)*f(0)

    assert f(x).diff(x).subs(x, 0).subs(x, y) == f(x).diff(x).subs(x, 0)
    assert (x*f(x).diff(x).subs(x, 0)).subs(x, y) == y*f(x).diff(x).subs(x, 0)
    assert Subs(Derivative(g(x)**2, g(x), x), g(x), exp(x)
        ).doit() == 2*exp(x)
    assert Subs(Derivative(g(x)**2, g(x), x), g(x), exp(x)
        ).doit(deep=False) == 2*Derivative(exp(x), x)
    assert Derivative(f(x, g(x)), x).doit() == Derivative(
        f(x, g(x)), g(x))*Derivative(g(x), x) + Subs(Derivative(
        f(y, g(x)), y), y, x)

