# @cctt_verify {"v":2,"sym":"sympy.core.tests.test_function.test_klein_gordon_lagrangian","kind":"function","src_hash":"47360396adb9acf2","in":{"base":"Any"},"out":{"base":"Any","pred":"eqna == eqnb"},"spec":{"lhs":"test_klein_gordon_lagrangian()","rhs":"test_klein_gordon_lagrangian produces the expected output","over":{"base":"Any"},"name":"test_klein_gordon_lagrangian_correct"},"guarantee":"test_klein_gordon_lagrangian produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.core.tests.test_function.test_klein_gordon_lagrangian_correct","statement":"Path(test_klein_gordon_lagrangian(x), test_klein_gordon_lagrangian produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"88eab4c9d228f4b9"}
def test_klein_gordon_lagrangian():
    m = Symbol('m')
    phi = f(x, t)

    L = -(diff(phi, t)**2 - diff(phi, x)**2 - m**2*phi**2)/2
    eqna = Eq(
        diff(L, phi) - diff(L, diff(phi, x), x) - diff(L, diff(phi, t), t), 0)
    eqnb = Eq(diff(phi, t, t) - diff(phi, x, x) + m**2*phi, 0)
    assert eqna == eqnb


