# @cctt_verify {"v":2,"sym":"sympy.core.tests.test_function.test_sho_lagrangian","kind":"function","src_hash":"9506a5112add5c66","in":{"base":"Any"},"out":{"base":"Any","pred":"eqna == eqnb and diff(L, x, t) == diff(L, t, x) and diff(L, diff(x, t), t) == m * diff(x, t, 2) and diff(L, t, diff(x, t)) == -k * x + m * diff(x, t, 2)"},"spec":{"lhs":"test_sho_lagrangian()","rhs":"test_sho_lagrangian produces the expected output","over":{"base":"Any"},"name":"test_sho_lagrangian_correct"},"guarantee":"test_sho_lagrangian produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.core.tests.test_function.test_sho_lagrangian_correct","statement":"Path(test_sho_lagrangian(x), test_sho_lagrangian produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"c8129ca96c1113a7"}
def test_sho_lagrangian():
    m = Symbol('m')
    k = Symbol('k')
    x = f(t)

    L = m*diff(x, t)**2/2 - k*x**2/2
    eqna = Eq(diff(L, x), diff(L, diff(x, t), t))
    eqnb = Eq(-k*x, m*diff(x, t, t))
    assert eqna == eqnb

    assert diff(L, x, t) == diff(L, t, x)
    assert diff(L, diff(x, t), t) == m*diff(x, t, 2)
    assert diff(L, t, diff(x, t)) == -k*x + m*diff(x, t, 2)


