# @cctt_verify {"v":2,"sym":"sympy.core.tests.test_function.test_Subs_Derivative","kind":"function","src_hash":"7b7dba3b99bfdda8","in":{"base":"Any"},"out":{"base":"Any","pred":"all((subs(i).doit().expand() == ans for i in eqs)) and all((subs(i.doit()).doit().expand() == ans for i in eqs))"},"spec":{"lhs":"test_Subs_Derivative()","rhs":"test_Subs_Derivative produces the expected output","over":{"base":"Any"},"name":"test_Subs_Derivative_correct"},"guarantee":"test_Subs_Derivative produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.core.tests.test_function.test_Subs_Derivative_correct","statement":"Path(test_Subs_Derivative(x), test_Subs_Derivative produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"feabbc3aad309ece"}
def test_Subs_Derivative():
    a = Derivative(f(g(x), h(x)), g(x), h(x),x)
    b = Derivative(Derivative(f(g(x), h(x)), g(x), h(x)),x)
    c = f(g(x), h(x)).diff(g(x), h(x), x)
    d = f(g(x), h(x)).diff(g(x), h(x)).diff(x)
    e = Derivative(f(g(x), h(x)), x)
    eqs = (a, b, c, d, e)
    subs = lambda arg: arg.subs(f, Lambda((x, y), exp(x + y))
        ).subs(g(x), 1/x).subs(h(x), x**3)
    ans = 3*x**2*exp(1/x)*exp(x**3) - exp(1/x)*exp(x**3)/x**2
    assert all(subs(i).doit().expand() == ans for i in eqs)
    assert all(subs(i.doit()).doit().expand() == ans for i in eqs)

